# ❌ ANTI-PATTERN: Uncontrolled agent chaining with no timeout or consensus check
class MatchOrchestrator:
    def plan_innings(self, batting_order):
        # Agents loop infinitely negotiating with no exit condition
        while True:
            batting_agent_response = self.batting_agent.propose_strategy(batting_order)
            bowling_agent_response = self.bowling_agent.counter_propose(batting_agent_response)
            if batting_agent_response == bowling_agent_response:
                break  # ⚠️ May never happen; no timeout, memory bloat
        return batting_agent_response

# ✅ BEST PRACTICE: Hierarchical with explicit delegation and timeout
class CaptainOrchestrator:
    def __init__(self, max_consensus_rounds=5, timeout_seconds=30):
        self.max_rounds = max_consensus_rounds
        self.timeout = timeout_seconds
        self.captain_agent = CaptainAgent()
        self.batting_agent = BattingSpecialist()
        self.bowling_agent = BowlingSpecialist()

    def orchestrate_match_plan(self, pitch_data, player_stats):
        # Captain analyzes, then delegates with clear scope
        captain_directive = self.captain_agent.analyze_match(
            pitch_data, player_stats
        )

        # Specialists execute within boundaries
        batting_plan = self.batting_agent.execute(
            scope=captain_directive["batting_scope"],
            constraints=captain_directive["constraints"],
            timeout=self.timeout
        )

        bowling_plan = self.bowling_agent.execute(
            scope=captain_directive["bowling_scope"],
            constraints=captain_directive["constraints"],
            timeout=self.timeout
        )

        # Captain final approval (no infinite loops)
        return self.captain_agent.approve_and_finalize(
            batting_plan, bowling_plan
        )

# ✅ CONSENSUS PATTERN: Explicit round limit + convergence check
def negotiate_field_placement(captain_pref, bowler_pref, max_rounds=4):
    consensus_history = []

    for round_num in range(max_rounds):
        # Both agents propose, track agreement score
        captain_proposal = captain_agent.propose(round_num, consensus_history)
        bowler_proposal = bowler_agent.propose(round_num, consensus_history)

        agreement_score = similarity(captain_proposal, bowler_proposal)
        consensus_history.append({
            "round": round_num,
            "captain": captain_proposal,
            "bowler": bowler_proposal,
            "agreement": agreement_score
        })

        # Early exit if consensus reached
        if agreement_score > 0.85:  # 85% threshold
            return merge_proposals(captain_proposal, bowler_proposal)

    # Fallback: captain breaks tie (hierarchical override)
    return captain_agent.break_tie(consensus_history)
